// 1920x1080 fullscreen installation
// Upgrades:
// - Background text fragments are generated by AI each round (/api/wordfield)
// - Background rendered as a tilted 3D-ish word plane (like the reference image)

const W = 1920;
const H = 1080;

let round = 0;
let totalRounds = 10;

let askCount = 0;
let shakeAmp = 0;        // accumulates with Ask AI
let shakePulse = 0;      // one-shot pulse
let vapor = 0;           // subtle vaporwave/glitch strength

let questionText = "Loading...";
let tags = { type: "general", difficulty: 2, uncertainty: 2 };

let uiQuestion, uiMeta, btnThink, btnAI;

let injector;
let brain;

// -------- wordfield 3D-ish plane --------
let wordGrid = [];
let gridCols = 64;
let gridRows = 34;

let bgItems = []; // AI-generated text fragments
let vocabFallback = [
  "why","how","plan","rewrite","summarize","translate","improve","explain","ideas","code",
  "deadline","focus","brain","habit","effort","uncertainty","fast","answer","verify","think",
  "prompt","result","logic","structure","argument","example","outline","study","work","email",
  "creative","title","tone","clarity","simple","complex","shortcut","default","pattern"
];

let plane = {
  cx: () => width * 0.56,
  cy: () => height * 0.58,
  w: () => width * 1.05,
  h: () => height * 0.78,
  tilt: 0.86,     // closer to reference
  yaw: -0.28
};

function setup() {
  createCanvas(W, H);
  frameRate(60);

  uiQuestion = document.getElementById("question");
  uiMeta = document.getElementById("meta");
  btnThink = document.getElementById("btn-think");
  btnAI = document.getElementById("btn-ai");

  btnThink.onclick = () => choose(false);
  btnAI.onclick = () => choose(true);

  brain = new BrainShape(width * 0.52, height * 0.50, 520, 360);
  injector = new Syringe(brain);

  initWordGrid(); // start with fallback; will be replaced by AI on first round
  nextRound();
}

function draw() {
  // camera shake
  let sx = 0, sy = 0;
  let amp = shakeAmp + shakePulse;
  if (amp > 0.001) {
    sx = (noise(frameCount * 0.08) - 0.5) * amp;
    sy = (noise(999 + frameCount * 0.08) - 0.5) * amp;
  }
  shakePulse *= 0.88;
  shakeAmp *= 0.995;
  vapor *= 0.99;

  push();
  translate(sx, sy);

  background(245);

  // background word plane
  drawWordField3D();

  // stage behind brain
  brain.drawStage();
  injector.draw();

  brain.drawOutline();
  brain.drawFill();
  brain.drawGyriLines();

  drawGlitchOverlay();

  if (round >= totalRounds) {
    drawEndOverlay();
  }

  pop();
}

// ------------------ ROUND FLOW ------------------
async function nextRound() {
  round++;
  if (round > totalRounds) {
    btnThink.disabled = true;
    btnAI.disabled = true;
    uiMeta.innerText = `Done.`;
    return;
  }

  uiMeta.innerText = `Round ${round}/${totalRounds} — AskAI: ${askCount}`;
  uiQuestion.innerText = "Generating a question…";

  try {
    const res = await fetch(`/api/question?round=${round}`);
    const data = await res.json();
    questionText = data.question || "Give me a realistic question people ask AI.";
    tags = data.tags || tags;

    uiQuestion.innerText = questionText;
    uiMeta.innerText = `Round ${round}/${totalRounds} — type: ${tags.type}, difficulty: ${tags.difficulty}, uncertainty: ${tags.uncertainty} — AskAI: ${askCount}`;

    // refresh background fragments for each round
    await refreshWordFieldFromAI();
  } catch (e) {
    questionText = "Give me a realistic question people ask AI.";
    uiQuestion.innerText = questionText;
  }
}

function choose(useAI) {
  if (round > totalRounds) return;

  if (useAI) {
    askCount++;

    injector.injectBurst();

    // twitch/glitch increases with addiction
    shakePulse = 18 + askCount * 2.5;
    shakeAmp += 5 + askCount * 1.2;
    vapor += 0.35;

    brain.addDose(1);
  } else {
    shakePulse = 2;
    vapor += 0.05;
  }

  nextRound();
}

// ------------------ AI WORD FIELD FETCH ------------------
async function refreshWordFieldFromAI() {
  const topic = encodeURIComponent((questionText || "").slice(0, 80));
  const url = `/api/wordfield?round=${round}&count=280&topic=${topic}`;

  try {
    const res = await fetch(url);
    const data = await res.json();
    bgItems = Array.isArray(data.items) ? data.items : [];

    // update grid texts immediately
    if (bgItems.length) {
      for (let idx = 0; idx < wordGrid.length; idx++) {
        wordGrid[idx].t = bgItems[idx % bgItems.length];
      }
    }
  } catch (e) {
    // keep old
  }
}

// ------------------ 3D-ish WORD PLANE ------------------
function initWordGrid() {
  wordGrid = [];
  for (let j = 0; j < gridRows; j++) {
    for (let i = 0; i < gridCols; i++) {
      const t = bgItems.length ? bgItems[(i + j * gridCols) % bgItems.length] : random(vocabFallback);
      wordGrid.push({
        t,
        u: i / (gridCols - 1),
        v: j / (gridRows - 1),
        z0: random(0.0, 1.0),
        n: random(1000),
        fs: random(10, 18),
        a: random(35, 90)
      });
    }
  }
}

function proj(u, v, z) {
  const px = (u - 0.5) * plane.w();
  const py = (v - 0.5) * plane.h();

  const far = (1.0 - v);
  const persp = 0.35 + 0.85 * (1.0 - far * plane.tilt);

  const x = plane.cx() + (px + py * plane.yaw) * persp;
  const y = plane.cy() + (py * (0.30 + 0.70 * (1.0 - plane.tilt * 0.55))) * persp;

  const lift = z * 320 * (0.35 + 0.65 * persp);
  return { x, y: y - lift, baseY: y, persp };
}

function drawWordField3D() {
  // frame
  push();
  noFill();
  stroke(0, 30);
  strokeWeight(1.2);
  const p00 = proj(0, 0, 0);
  const p10 = proj(1, 0, 0);
  const p11 = proj(1, 1, 0);
  const p01 = proj(0, 1, 0);
  beginShape();
  vertex(p00.x, p00.baseY);
  vertex(p10.x, p10.baseY);
  vertex(p11.x, p11.baseY);
  vertex(p01.x, p01.baseY);
  endShape(CLOSE);
  pop();

  // sort far->near
  const cells = [...wordGrid].sort((a, b) => a.v - b.v);

  for (const c of cells) {
    const wave = noise(c.n + frameCount * 0.01) * 1.0;
    const twitch = (vapor * 0.8 + shakePulse * 0.02) * noise(c.n + frameCount * 0.12);
    let z = c.z0 * 0.6 + wave * 0.5 + twitch;
    z = constrain(z, 0, 2.2);

    const p = proj(c.u, c.v, z);

    // pillar
    stroke(0, 35);
    strokeWeight(1);
    line(p.x, p.baseY, p.x, p.y);

    // text top
    noStroke();
    fill(0, c.a);
    textSize(c.fs * (0.55 + 0.65 * p.persp));
    text(c.t, p.x, p.y);

    // tiny drift - optional
    if (random() < 0.00015 && bgItems.length) c.t = bgItems[floor(random(bgItems.length))];
  }
}

// ------------------ GLITCH + END OVERLAY ------------------
function drawGlitchOverlay() {
  if (askCount <= 0) return;

  const strength = constrain(askCount / totalRounds, 0, 1);
  const lines = floor(8 + strength * 26);

  noStroke();
  for (let i = 0; i < lines; i++) {
    const y = random(height);
    const h = random(2, 8);
    const a = 10 + strength * 35;
    fill(120 + random(-20, 20), 40 + random(-10, 10), 120 + random(-20, 20), a);
    rect(0, y, width, h);
  }
}

function drawEndOverlay() {
  const rate = askCount / totalRounds;
  const pct = Math.round(rate * 100);

  if (rate > 0.5) {
    shakeAmp += 0.25;
    vapor += 0.02;
  }

  push();
  noStroke();
  fill(255, 240);
  rect(width * 0.06, height * 0.06, width * 0.40, 140, 18);

  fill(0, 220);
  textSize(28);
  text(`AI Addiction Rate: ${pct}%`, width * 0.08, height * 0.11);

  textSize(14);
  text(
    `Ask AI ${askCount}/${totalRounds}\n(visual intensity + brain saturation scale with this rate)`,
    width * 0.08,
    height * 0.14
  );
  pop();

  brain.forceFillTo(rate);
}

// ------------------ BRAIN + INJECTION ------------------
class BrainShape {
  constructor(cx, cy, w, h) {
    this.cx = cx; this.cy = cy;
    this.w = w; this.h = h;
    this.fillLevel = 0;
    this.targetFill = 0;
    this.doses = 0;
    this.aiBlobs = [];
  }

  drawStage() {
    push();
    noStroke();
    fill(255, 230);
    rect(this.cx - this.w * 0.62, this.cy - this.h * 0.62, this.w * 1.24, this.h * 1.24, 26);
    pop();
  }

  outlinePath() {
    const x = this.cx, y = this.cy, w = this.w, h = this.h;
    beginShape();
    vertex(x - w*0.45, y - h*0.12);
    bezierVertex(x - w*0.42, y - h*0.45, x + w*0.10, y - h*0.52, x + w*0.40, y - h*0.30);
    bezierVertex(x + w*0.60, y - h*0.12, x + w*0.55, y + h*0.25, x + w*0.30, y + h*0.35);
    bezierVertex(x + w*0.15, y + h*0.45, x - w*0.15, y + h*0.42, x - w*0.30, y + h*0.30);
    bezierVertex(x - w*0.55, y + h*0.15, x - w*0.55, y + h*0.02, x - w*0.45, y - h*0.12);
    endShape(CLOSE);
  }

  drawOutline() {
    push();
    stroke(20);
    strokeWeight(10);
    noFill();
    this.outlinePath();
    pop();
  }

  drawGyriLines() {
    push();
    stroke(40, 120);
    strokeWeight(5);
    noFill();

    const x = this.cx, y = this.cy, w = this.w, h = this.h;

    curveLine(x - w*0.30, y - h*0.10, x - w*0.10, y - h*0.28, x + w*0.10, y - h*0.18, x + w*0.25, y - h*0.05);
    curveLine(x - w*0.28, y + h*0.05, x - w*0.05, y - h*0.05, x + w*0.18, y + h*0.02, x + w*0.30, y + h*0.12);
    curveLine(x - w*0.15, y + h*0.20, x + w*0.05, y + h*0.15, x + w*0.20, y + h*0.22, x + w*0.28, y + h*0.08);

    pop();
  }

  drawFill() {
    this.fillLevel = lerp(this.fillLevel, this.targetFill, 0.06);
    this.updateBlobs();

    push();
    // draw blobs inside brain
    for (const b of this.aiBlobs) {
      if (this.isInsideBrain(b.x, b.y)) b.draw();
    }

    // saturation wash based on fill
    const sat = 40 + this.fillLevel * 160;
    noStroke();
    fill(120, 40, 120, sat);
    this.outlinePath();
    pop();
  }

  isInsideBrain(px, py) {
    const dx = (px - this.cx) / (this.w * 0.52);
    const dy = (py - this.cy) / (this.h * 0.45);
    const e = dx*dx + dy*dy;

    const bulge = ((px - (this.cx - this.w*0.12)) / (this.w*0.55))**2 +
                  ((py - (this.cy - this.h*0.10)) / (this.h*0.55))**2;

    return (e < 1.05) || (bulge < 1.0);
  }

  addDose(n) {
    this.doses += n;
    this.targetFill = constrain(this.doses / totalRounds, 0, 1);
  }

  forceFillTo(rate) {
    this.targetFill = max(this.targetFill, rate);
    const desired = Math.floor(50 + rate * 260);
    while (this.aiBlobs.length < desired) {
      this.aiBlobs.push(new AIBlob(
        random(this.cx - this.w*0.45, this.cx + this.w*0.45),
        random(this.cy - this.h*0.25, this.cy + this.h*0.35),
        random(0.8, 2.0)
      ));
    }
  }

  spawnInjectionStream(startX, startY, endX, endY) {
    const count = 28;
    for (let i = 0; i < count; i++) {
      const t = i / (count - 1);
      const x = lerp(startX, endX, t) + random(-8, 8);
      const y = lerp(startY, endY, t) + random(-8, 8);
      const b = new AIBlob(x, y, random(1.0, 2.2));
      b.vx = random(-0.2, 0.2);
      b.vy = random(0.6, 1.4);
      b.life = 240 + random(-40, 80);
      this.aiBlobs.push(b);
    }

    if (this.aiBlobs.length > 420) {
      this.aiBlobs.splice(0, this.aiBlobs.length - 420);
    }
  }

  updateBlobs() {
    for (let i = 0; i < this.aiBlobs.length; i++) {
      const b = this.aiBlobs[i];

      b.vy += 0.03;
      b.vx *= 0.985;
      b.vy *= 0.985;

      const dx = this.cx - b.x;
      const dy = (this.cy + this.h*0.10) - b.y;
      b.vx += dx * 0.00025;
      b.vy += dy * 0.00015;

      b.x += b.vx;
      b.y += b.vy;

      if (b.x < this.cx - this.w*0.52) b.vx *= -0.5;
      if (b.x > this.cx + this.w*0.52) b.vx *= -0.5;

      b.life -= 1;
    }

    this.aiBlobs = this.aiBlobs.filter(b => b.life > 0);
  }
}

function curveLine(x1,y1,cx1,cy1,x2,y2,x3,y3) {
  beginShape();
  vertex(x1,y1);
  bezierVertex(cx1,cy1,x2,y2,x3,y3);
  endShape();
}

class AIBlob {
  constructor(x, y, s) {
    this.x = x; this.y = y; this.s = s;
    this.vx = random(-0.2, 0.2);
    this.vy = random(0.1, 0.5);
    this.life = 260;
    this.rot = random(-0.4, 0.4);
  }

  draw() {
    push();
    translate(this.x, this.y);
    rotate(this.rot + sin(frameCount * 0.03) * 0.05);

    fill(20, 200);
    noStroke();
    textSize(24 * this.s);
    textStyle(BOLD);
    text("AI", 0, 0);

    // glossy highlight
    fill(255, 60);
    ellipse(10 * this.s, -8 * this.s, 16 * this.s, 10 * this.s);

    pop();
  }
}

class Syringe {
  constructor(brain) {
    this.brain = brain;
    this.baseX = brain.cx + brain.w * 0.55;
    this.baseY = brain.cy - brain.h * 0.05;
    this.tipX = brain.cx + brain.w * 0.38;
    this.tipY = brain.cy - brain.h * 0.05;
    this.plunger = 0;
  }

  injectBurst() {
    this.plunger = 1.0;
    this.brain.spawnInjectionStream(
      this.tipX,
      this.tipY,
      this.brain.cx + this.brain.w*0.18,
      this.brain.cy + this.brain.h*0.12
    );
  }

  draw() {
    this.plunger *= 0.86;

    push();
    noStroke();
    fill(255);
    rect(this.baseX - 140, this.baseY - 22, 160, 44, 10);

    stroke(0, 50);
    strokeWeight(2);
    noFill();
    rect(this.baseX - 140, this.baseY - 22, 160, 44, 10);

    noStroke();
    fill(230);
    const px = this.baseX - 140 - 26 + (1 - this.plunger) * 10;
    rect(px, this.baseY - 14, 26, 28, 8);

    stroke(0, 70);
    strokeWeight(3);
    line(this.baseX + 20, this.baseY, this.tipX, this.tipY);

    stroke(0, 120);
    strokeWeight(2);
    line(this.tipX, this.tipY, this.tipX - 16, this.tipY + 6);
    pop();
  }
}